import{_ as e,o as r,c as o,a2 as t}from"./chunks/framework.DnrXFDHb.js";const u=JSON.parse('{"title":"F11: 處分重大資產與資本配置 - 財務審計專家報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/財務審計/6239_力成/20260617/F11_處分重大資產與資本配置.md","filePath":"審計報告庫/財務審計/6239_力成/20260617/F11_處分重大資產與資本配置.md"}'),l={name:"審計報告庫/財務審計/6239_力成/20260617/F11_處分重大資產與資本配置.md"};function i(n,a,h,s,d,c){return r(),o("div",null,[...a[0]||(a[0]=[t('<h1 id="f11-處分重大資產與資本配置-財務審計專家報告" tabindex="-1">F11: 處分重大資產與資本配置 - 財務審計專家報告 <a class="header-anchor" href="#f11-處分重大資產與資本配置-財務審計專家報告" aria-label="Permalink to &quot;F11: 處分重大資產與資本配置 - 財務審計專家報告&quot;">​</a></h1><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><blockquote><p>是否存在處分重大資產之行為？處分損益佔比為何？資金用途是投入再投資還是為了彌補虧損？</p></blockquote><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><ul><li><strong>核心結論</strong>：2023-2025年無重大資產處分，業外處分利益2.37億為設備汰換常態。資本配置聚焦先進封裝，退出低毛利Power Module業務，方向正確。</li><li><strong>風險評級</strong>：低</li><li><strong>數據時效</strong>：根據截至2025年最新年報數據</li></ul><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><p>2025年處分不動產廠房設備利益2.37億（現金流量表處分價款2.35億），較2024年2.34億大致持平，屬年度例行性設備汰換。其他利益及損失6.10億中包含金融資產利益0.79億、金融負債損失-0.40億、減損損失-0.38億（Tera Probe設備減損），扣除後核心營業外利益約3.73億。整體業外6.60億/稅前淨利87.9億=7.5%，處分資產僅佔2.7%，均在安全水位。無子公司股權或核心技術資產處分記錄。</p><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><h3 id="獲利含金量穿透" tabindex="-1">獲利含金量穿透 <a class="header-anchor" href="#獲利含金量穿透" aria-label="Permalink to &quot;獲利含金量穿透&quot;">​</a></h3><p>扣除一次性項目（處分資產利益2.37億+減損-0.38億+金融資產評價0.39億）後，常態性業外約4.22億。2025年扣除非經常性項目後的調整營益率約10.9%（與帳面一致，因非經常項目僅影響業外），本業獲利純度極高。無處分子公司或重大廠房之情事，唯一重大資產交易為6.9億購入友達新竹廠房（屬擴產買入，非賣出）。</p><h3 id="戰略意圖判別" tabindex="-1">戰略意圖判別 <a class="header-anchor" href="#戰略意圖判別" aria-label="Permalink to &quot;戰略意圖判別&quot;">​</a></h3><p>力成2025年CapEx 260.2億的資金來源：CFO 167.0億（64%）、舉借長債144.5億（56%）。資金用途：(1)FOPLP先進封裝設備；(2)光引擎Optical Engine；(3)購入友達廠房6.9億；(4)Tera Probe/Tera Power測試產能擴充。策略明確為「進攻型擴產」，非「生存型變現」。管理層法說會表示寧可策略性退出低毛利Power Module業務，也要將資源集中於高階封裝。</p><h3 id="股利政策檢查" tabindex="-1">股利政策檢查 <a class="header-anchor" href="#股利政策檢查" aria-label="Permalink to &quot;股利政策檢查&quot;">​</a></h3><p>2024年現金股利7.0元（盈餘配發率77%），2025年擬議現金股利4.5元（配發率約63%，按EPS 7.10元計算），配發率下降但保留盈餘用於擴產。資金未用於「祖產派現」，符合F08擴產敘事的一致性。子公司超豐持有力成20,350張庫藏股（帳面35.2億），間接支持股價。</p><h2 id="💡-專家評析-多空雙向分析" tabindex="-1">💡 專家評析（多空雙向分析） <a class="header-anchor" href="#💡-專家評析-多空雙向分析" aria-label="Permalink to &quot;💡 專家評析（多空雙向分析）&quot;">​</a></h2><h3 id="🔴-空方觀點-利空風險" tabindex="-1">🔴 空方觀點（利空風險） <a class="header-anchor" href="#🔴-空方觀點-利空風險" aria-label="Permalink to &quot;🔴 空方觀點（利空風險）&quot;">​</a></h3><ol><li><strong>減損損失可能擴大</strong>：2025年Tera Probe設備減損0.38億（前年0.11億），若先進封裝設備折舊加速時發生技術路線變更，可能需進一步減損。</li><li><strong>CapEx資金來源過度依賴舉債</strong>：CFO僅能覆蓋CapEx的64%，其餘36%靠舉債，若持續2-3年融資成本上升將壓縮獲利。</li></ol><h3 id="🟢-多方觀點-機會可能性" tabindex="-1">🟢 多方觀點（機會可能性） <a class="header-anchor" href="#🟢-多方觀點-機會可能性" aria-label="Permalink to &quot;🟢 多方觀點（機會可能性）&quot;">​</a></h3><ol><li><strong>無祖產變賣的純粹成長敘事</strong>：力成近三年無出售核心資產或子公司獲利美化財報的記錄，處分僅為設備汰換，資本配置紀律良好。</li><li><strong>資金投入先進封裝具高回報潛力</strong>：每年122億折舊透過設備更新維持技術競爭力，CapEx集中於FOPLP、HBM等AI相關封測，若2027年量產成功，ROI可望顯著超越資金成本。</li></ol><h3 id="⚖️-綜合權衡" tabindex="-1">⚖️ 綜合權衡 <a class="header-anchor" href="#⚖️-綜合權衡" aria-label="Permalink to &quot;⚖️ 綜合權衡&quot;">​</a></h3><p>力成無處分重大資產之疑慮，資本配置策略清晰——集中資源於先進封裝、策略性退出低毛利業務、保留盈餘支援擴產。資金來源雖有舉債但仍可控。屬於「擴張型配置」而非「防禦型求生」。</p><h2 id="📚-證據來源" tabindex="-1">📚 證據來源 <a class="header-anchor" href="#📚-證據來源" aria-label="Permalink to &quot;📚 證據來源&quot;">​</a></h2><ul><li>計算工具：數據採集器.py (cash_flow 6239, finance 6239)</li><li>原始數據：FinMind TaiwanStockCashFlowsStatement</li><li>查詢參數：stock_id=6239, start=2022-01-01, end=2025-12-31</li><li>年報數據：2025_Q4_6239_合併.pdf (pages 9、12-13、39、53，損益表、現金流量表、PP&amp;E附註)</li><li>數據查詢日期：2026-06-17</li></ul>',23)])])}const p=e(l,[["render",i]]);export{u as __pageData,p as default};
